local cjson = require "cjson"
local xml = require "xml"

local function parse_xml_entity(text)
    if not text then return text end
    
    local entities = {
        ["&lt;"] = "<",
        ["&gt;"] = ">",
        ["&amp;"] = "&",
        ["&quot;"] = '"',
        ["&apos;"] = "'",
        ["&#(%d+);"] = function(n) return string.char(tonumber(n)) end,
        ["&#x(%x+);"] = function(n) return string.char(tonumber(n, 16)) end
    }
    
    for pattern, replacement in pairs(entities) do
        if type(replacement) == "function" then
            text = text:gsub(pattern, replacement)
        else
            text = text:gsub(pattern, replacement)
        end
    end
    
    return text
end

local function parse_xml_simple(xml_string)
    local stack = {}
    local root = nil
    local current = nil
    
    xml_string = xml_string:gsub("<%?xml.-%?>", "")
    xml_string = xml_string:gsub("<!%-.-%->", "")
    
    for tag_start, tag_name, attrs, tag_end, content in xml_string:gmatch("<(/?)([%w:_%-]+)([^>]-)(/?)>([^<]*)") do
        if tag_start == "" and tag_end ~= "/" then
            local node = {
                name = tag_name,
                attrs = {},
                children = {},
                text = ""
            }
            
            for attr_name, attr_value in attrs:gmatch('([%w:_%-]+)%s*=%s*["\']([^"\']*)["\']') do
                node.attrs[attr_name] = parse_xml_entity(attr_value)
            end
            
            if current then
                table.insert(current.children, node)
                table.insert(stack, current)
            else
                root = node
            end
            current = node
            
        elseif tag_start == "/" then
            if current then
                current = table.remove(stack)
            end
            
        elseif tag_end == "/" then
            local node = {
                name = tag_name,
                attrs = {},
                children = {},
                text = ""
            }
            
            for attr_name, attr_value in attrs:gmatch('([%w:_%-]+)%s*=%s*["\']([^"\']*)["\']') do
                node.attrs[attr_name] = parse_xml_entity(attr_value)
            end
            
            if current then
                table.insert(current.children, node)
            else
                root = node
            end
        end
        
        if content and content ~= "" then
            local trimmed = content:match("^%s*(.-)%s*$")
            if current and trimmed ~= "" then
                current.text = (current.text or "") .. parse_xml_entity(trimmed)
            end
        end
    end
    
    return root
end

local function find_node(node, name)
    if not node then return nil end
    
    if node.name == name then
        return node
    end
    
    for _, child in ipairs(node.children or {}) do
        local found = find_node(child, name)
        if found then return found end
    end
    
    return nil
end

local function find_nodes(node, name, results)
    results = results or {}
    
    if not node then return results end
    
    if node.name == name then
        table.insert(results, node)
    end
    
    for _, child in ipairs(node.children or {}) do
        find_nodes(child, name, results)
    end
    
    return results
end

local function node_text(node)
    if not node then return nil end
    
    if node.text and node.text ~= "" then
        return node.text
    end
    
    if #node.children == 1 and node.children[1].text then
        return node.children[1].text
    end
    
    return nil
end

local function extract_soap_body(xml_doc)
    local body = find_node(xml_doc, "Body") or 
                 find_node(xml_doc, "soap:Body") or
                 find_node(xml_doc, "soapenv:Body") or
                 find_node(xml_doc, "SOAP-ENV:Body")
    
    if body and #body.children > 0 then
        return body.children[1]
    end
    
    return nil
end

local function xml_to_table(node)
    if not node then return nil end
    
    local result = {}
    
    result._name = node.name
    
    for k, v in pairs(node.attrs or {}) do
        result["@" .. k] = v
    end
    
    if node.text and node.text ~= "" and #node.children == 0 then
        return node.text
    end
    
    local child_groups = {}
    for _, child in ipairs(node.children or {}) do
        local child_name = child.name
        if not child_groups[child_name] then
            child_groups[child_name] = {}
        end
        table.insert(child_groups[child_name], child)
    end
    
    for name, children in pairs(child_groups) do
        if #children == 1 then
            result[name] = xml_to_table(children[1])
        else
            result[name] = {}
            for _, child in ipairs(children) do
                table.insert(result[name], xml_to_table(child))
            end
        end
    end
    
    return result
end

